      generation: current.generation + 1,
      updatedAt: new Date().toISOString(),
      sourceSignature: options.sourceSignature ?? null,
      reason: options.reason,
      state: options.state ?? 'live',
    };
    writeJsonAtomic(generationPath, metadata);
